{"file_text": "<div class="step-content">
    <h3>Cover Letter</h3>

    <div class="form-group">
        <label>Write your cover letter</label>
        <textarea class="form-control cover-letter-textarea"
                  rows="12"
                  maxlength="@MaxLength"
                  @bind="coverLetterValue"
                  @bind:event="oninput"></textarea>
        <div class="character-count @(coverLetterValue.Length > MaxLength ? "over-limit" : "")">
            @coverLetterValue.Length / @MaxLength characters
        </div>
    </div>

    <div class="step-buttons">
        <button type="button" class="btn btn-outline" @onclick="HandleBack">← Back</button>
        <button type="button" class="btn btn-primary" @onclick="HandleNext">Next →</button>
    </div>
</div>

@code {
    [Parameter] public string CoverLetter { get; set; } = "";
    [Parameter] public EventCallback<string> CoverLetterChanged { get; set; }
    [Parameter] public EventCallback OnNext { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }

    private const int MaxLength = 2000;
    private string coverLetterValue = "";

    protected override void OnParametersSet()
    {
        coverLetterValue = CoverLetter;
    }

    private async Task HandleNext()
    {
        await CoverLetterChanged.InvokeAsync(coverLetterValue);
        await OnNext.InvokeAsync();
    }

    private async Task HandleBack()
    {
        await CoverLetterChanged.InvokeAsync(coverLetterValue);
        await OnBack.InvokeAsync();
    }
}
