@using sv_71d19b16e7ab484f89bffa91f786824d.Models

<div class="step-indicator">
    @for (int i = 0; i < StepNames.Count; i++)
    {
        var step = i + 1;
        var status = step == CurrentStep ? "active"
                   : CompletedSteps.Contains(step) ? "completed"
                   : "pending";
        var clickable = CompletedSteps.Contains(step) && step != CurrentStep;

        <div class="step @status" @onclick="() => { if (clickable) OnStepClicked.InvokeAsync(step); }" style="@(clickable ? "cursor:pointer" : "")">
            <div class="step-circle">
                @if (CompletedSteps.Contains(step) && step != CurrentStep)
                {
                    <span>✓</span>
                }
                else
                {
                    <span>@step</span>
                }
            </div>
            <div class="step-label">@StepNames[i]</div>
        </div>

        @if (i < StepNames.Count - 1)
        {
            <div class="step-connector @(CompletedSteps.Contains(step) ? "completed" : "")"></div>
        }
    }
</div>

@code {
    [Parameter, EditorRequired] public int CurrentStep { get; set; }
    [Parameter, EditorRequired] public HashSet<int> CompletedSteps { get; set; } = new();
    [Parameter, EditorRequired] public List<string> StepNames { get; set; } = new();
    [Parameter] public EventCallback<int> OnStepClicked { get; set; }
}

