@using sv_71d19b16e7ab484f89bffa91f786824d.Models

<div class="step-content">
    <h3>Review & Submit</h3>

    @if (IsSubmitted)
    {
        <div class="confirmation">
            <div class="confirmation-icon">✓</div>
            <h4>Application Submitted!</h4>
            <p>Your application has been received. Your application ID is:</p>
            <div class="application-id">#@ApplicationId</div>
        </div>
    }
    else
    {
        <div class="review-section">
            <div class="review-header">
                <h4>Personal Information</h4>
                <button type="button" class="btn-link" @onclick="() => OnEditSection.InvokeAsync(1)">Edit</button>
            </div>
            <dl>
                <dt>Full Name</dt><dd>@Personal.FullName</dd>
                <dt>Email</dt><dd>@Personal.Email</dd>
                <dt>Phone</dt><dd>@Personal.Phone</dd>
                <dt>Address</dt><dd>@Personal.Address</dd>
            </dl>
        </div>

        <div class="review-section">
            <div class="review-header">
                <h4>Work History</h4>
                <button type="button" class="btn-link" @onclick="() => OnEditSection.InvokeAsync(2)">Edit</button>
            </div>
            @foreach (var entry in WorkEntries)
            {
                <div class="review-entry">
                    <strong>@entry.Title</strong> at <strong>@entry.Company</strong>
                    <div class="review-dates">
                        @entry.StartDate?.ToString("MMM yyyy") –
                        @(entry.IsCurrent ? "Present" : entry.EndDate?.ToString("MMM yyyy"))
                    </div>
                    @if (!string.IsNullOrWhiteSpace(entry.Description))
                    {
                        <p>@entry.Description</p>
                    }
                </div>
            }
        </div>

        <div class="review-section">
            <div class="review-header">
                <h4>References</h4>
                <button type="button" class="btn-link" @onclick="() => OnEditSection.InvokeAsync(3)">Edit</button>
            </div>
            @foreach (var r in References)
            {
                <div class="review-entry">
                    <strong>@r.Name</strong> — @r.Relationship
                    <div>@r.Email · @r.Phone</div>
                </div>
            }
        </div>

        <div class="review-section">
            <div class="review-header">
                <h4>Cover Letter</h4>
                <button type="button" class="btn-link" @onclick="() => OnEditSection.InvokeAsync(4)">Edit</button>
            </div>
            <div class="cover-letter-preview">@CoverLetter</div>
        </div>

        @if (!string.IsNullOrEmpty(submitError))
        {
            <div class="validation-message">@submitError</div>
        }

        <div class="step-buttons">
            <button type="button" class="btn btn-outline" @onclick="OnBack">← Back</button>
            <button type="button" class="btn btn-primary btn-submit" @onclick="HandleSubmit" disabled="@isSubmitting">
                @(isSubmitting ? "Submitting..." : "Submit Application")
            </button>
        </div>
    }
</div>

@code {
    [Parameter, EditorRequired] public PersonalInfoModel Personal { get; set; } = default!;
    [Parameter, EditorRequired] public List<WorkEntryModel> WorkEntries { get; set; } = default!;
    [Parameter, EditorRequired] public List<ReferenceModel> References { get; set; } = default!;
    [Parameter] public string CoverLetter { get; set; } = "";
    [Parameter, EditorRequired] public IApplicationService ApplicationService { get; set; } = default!;
    [Parameter] public EventCallback OnBack { get; set; }
    [Parameter] public EventCallback<int> OnEditSection { get; set; }
    [Parameter] public bool IsSubmitted { get; set; }
    [Parameter] public int ApplicationId { get; set; }
    [Parameter] public EventCallback<int> OnSubmitted { get; set; }

    private bool isSubmitting;
    private string? submitError;

    private async Task HandleSubmit()
    {
        isSubmitting = true;
        submitError = null;

        try
        {
            var application = new JobApplication(
                Personal.ToRecord(),
                new WorkHistory(WorkEntries.Select(e => e.ToRecord()).ToList()),
                References.Select(r => r.ToRecord()).ToList(),
                CoverLetter
            );

            var id = await ApplicationService.SubmitApplicationAsync(application);
            await OnSubmitted.InvokeAsync(id);
        }
        catch (Exception ex)
        {
            submitError = $"Submission failed: {ex.Message}";
        }
        finally
        {
            isSubmitting = false;
        }
    }
}

