}

.review-section dt {
    color: #6b7280;
    font-weight: 500;
}

.review-section dd {
    margin: 0;
}

.review-entry {
    margin-bottom: 0.75rem;
    font-size: 0.875rem;
}

.review-dates {
    color: #6b7280;
    font-size: 0.8rem;
}

.cover-letter-preview {
    white-space: pre-wrap;
    background: #f9fafb;
    padding: 0.75rem;
    border-radius: 6px;
    font-size: 0.875rem;
    max-height: 200px;
    overflow-y: auto;
}

/* ── Confirmation ── */
.confirmation {
    text-align: center;
    padding: 2rem 1rem;
}

.confirmation-icon {
