toolArgs.file_text:
@page "/apply"
@rendermode InteractiveServer
@using sv_71d19b16e7ab484f89bffa91f786824d.Models
@inject IApplicationService ApplicationService

<PageTitle>Job Application</PageTitle>

<div class="apply-container">
    <h2>Job Application</h2>

    <StepIndicator CurrentStep="currentStep"
                   CompletedSteps="completedSteps"
                   StepNames="stepNames"
                   OnStepClicked="GoToStep" />

    @switch (currentStep)
    {
        case 1:
            <PersonalInfoStep Personal="personal"
                              ApplicationService="ApplicationService"
                              OnNext="() => AdvanceToStep(2)" />
            break;

        case 2:
            <WorkHistoryStep Entries="workEntries"
                             OnNext="() => AdvanceToStep(3)"
                             OnBack="() => GoToStep(1)" />
            break;

        case 3:
            <ReferencesStep References="references"
                            OnNext="() => AdvanceToStep(4)"
                            OnBack="() => GoToStep(2)" />
            break;

        case 4:
            <CoverLetterStep CoverLetter="@coverLetter"
                             CoverLetterChanged="val => coverLetter = val"
                             OnNext="() => AdvanceToStep(5)"
                             OnBack="() => GoToStep(3)" />
            break;

        case 5:
            <ReviewStep Personal="personal"
                        WorkEntries="workEntries"
                        References="references"
                        CoverLetter="@coverLetter"
                        ApplicationService="ApplicationService"
                        IsSubmitted="isSubmitted"
                        ApplicationId="applicationId"
                        OnBack="() => GoToStep(4)"
                        OnEditSection="GoToStep"
                        OnSubmitted="HandleSubmitted" />
            break;
    }
</div>

@code {
    private int currentStep = 1;
    private readonly HashSet<int> completedSteps = new();
    private bool isSubmitted;
    private int applicationId;

    private readonly List<string> stepNames = new()
    {
        "Personal Info", "Work History", "References", "Cover Letter", "Review & Submit"
    };

    // Form state owned by the page
    private readonly PersonalInfoModel personal = new();
    private readonly List<WorkEntryModel> workEntries = new() { new WorkEntryModel() };
    private readonly List<ReferenceModel> references = new() { new ReferenceModel(), new ReferenceModel() };
    private string coverLetter = "";

    private void AdvanceToStep(int step)
    {
        completedSteps.Add(currentStep);
        currentStep = step;
    }

    private void GoToStep(int step)
    {
        currentStep = step;
    }

    private void HandleSubmitted(int id)
    {
        applicationId = id;
        isSubmitted = true;
        completedSteps.Add(5);
    }
}

